parameters.inputSchema:
{
  "title": "TripPlannerRequest",
  "type": "object",
  "required": [
    "error",
    "error_msg"
  ],
  "properties": {
    "origin": {
      "type": "string",
      "description": "City or airport code of departure"
    },
    "destination": {
      "type": "string",
      "description": "City or airport code of destination"
    },
    "departure_date": {
      "type": "string",
      "format": "date",
      "description": "Departure date in DD-MM-YYYY"
    },
    "return_date": {
      "type": "string",
      "format": "date",
      "description": "Return date in DD-MM-YYYY"
    },
    "error": {
      "type": "boolean",
      "description": "Set to true if the message is a greeting/small talk/unrelated to travel (no trip request present), OR if any of origin, destination, departure_date, return_date are missing. Set to false ONLY when the message is a real trip request AND all four of those fields are present."
    },
    "error_msg": {
      "type": "string",
      "description": "Required whenever error is true. For greetings/small talk: a warm message greeting the user back and asking for their trip details (origin, destination, departure and return dates). For an incomplete trip request: a friendly message listing the specific missing fields. Use an empty string when error is false."
    },
    "number_of_travelers": {
      "type": "integer",
      "minimum": 1,
      "default": 1
    },
    "budget": {
      "type": "number",
      "description": "Total trip budget in USD"
    },
    "travel_style": {
      "type": "string",
      "enum": [
        "budget",
        "mid-range",
        "luxury"
      ]
    },
    "preferences": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "User interests such as food, museums, nightlife, hiking"
    },
    "hotel_preferences": {
      "type": "object",
      "properties": {
        "star_rating_min": {
          "type": "number",
          "minimum": 1,
          "maximum": 5
        },
        "neighborhood": {
          "type": "string"
        }
      }
    },
    "flight_preferences": {
      "type": "object",
      "properties": {
        "nonstop_only": {
          "type": "boolean"
        },
        "preferred_airlines": {
          "type": "array",
          "items": {
            "type": "string"
          }
        }
      }
    }
  }
}
